1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = {
4	  customer: { yearsWithMHPCO: number };
5	  steps: Step[];
6	};
7	
8	const PROCESSING_FEE = 5;
9	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
10	const ITEM_BASE: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	};
17	
18	const quotePremium = ({ items }: Step): number => {
19	  const policyBase = items.reduce((sum, item) => sum + ITEM_BASE[item.type], 0);
20	  const firstContractSurcharge = policyBase * FIRST_CONTRACT_SURCHARGE_RATE;
21	  return policyBase + firstContractSurcharge + PROCESSING_FEE;
22	};
23	
24	export const runScenario = ({ steps }: Scenario): { results: unknown[] } => {
25	  const results = steps.map((step) => ({ premium: quotePremium(step) }));
26	  return { results };
27	};
